import { useEffect, useState } from "react";
import "./App.css";

const STORAGE_KEY = "crud-practice-products";

const DEFAULT_PRODUCTS = [
  {
    id: 101,
    name: "Mechanical Keyboard",
    category: "Accessories",
    price: 89.99,
    quantity: 12,
  },
  {
    id: 102,
    name: "27 inch Monitor",
    category: "Displays",
    price: 249.0,
    quantity: 4,
  },
  {
    id: 103,
    name: "USB-C Dock",
    category: "Workstation",
    price: 119.5,
    quantity: 7,
  },
];

const EMPTY_FORM = {
  name: "",
  category: "",
  price: "",
  quantity: "",
};

const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

function loadProducts() {
  if (typeof window === "undefined") {
    return DEFAULT_PRODUCTS;
  }

  const storedValue = window.localStorage.getItem(STORAGE_KEY);

  if (!storedValue) {
    return DEFAULT_PRODUCTS;
  }

  try {
    const parsedProducts = JSON.parse(storedValue);

    if (Array.isArray(parsedProducts)) {
      return parsedProducts;
    }
  } catch (error) {
    console.error("Could not read saved demo data.", error);
  }

  return DEFAULT_PRODUCTS;
}

function getStockLabel(quantity) {
  if (quantity === 0) {
    return "Out of stock";
  }

  if (quantity <= 5) {
    return "Low stock";
  }

  return "Healthy";
}

function getStockTone(quantity) {
  if (quantity === 0) {
    return "danger";
  }

  if (quantity <= 5) {
    return "warning";
  }

  return "success";
}

function App() {
  const [products, setProducts] = useState(loadProducts);
  const [form, setForm] = useState(EMPTY_FORM);
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [feedback, setFeedback] = useState(
    "Demo mode is active. Your products are saved in the browser until you connect FastAPI."
  );

  useEffect(() => {
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(products));
  }, [products]);

  const totalProducts = products.length;
  const totalUnits = products.reduce(
    (currentTotal, product) => currentTotal + product.quantity,
    0
  );
  const lowStockCount = products.filter((product) => product.quantity <= 5).length;
  const inventoryValue = products.reduce(
    (currentTotal, product) => currentTotal + product.price * product.quantity,
    0
  );

  const filteredProducts = [...products]
    .filter((product) => {
      const query = searchTerm.trim().toLowerCase();

      if (!query) {
        return true;
      }

      return (
        product.name.toLowerCase().includes(query) ||
        product.category.toLowerCase().includes(query)
      );
    })
    .sort((firstProduct, secondProduct) => secondProduct.id - firstProduct.id);

  const isEditing = editingId !== null;

  function resetForm() {
    setForm(EMPTY_FORM);
    setEditingId(null);
  }

  function handleInputChange(event) {
    const { name, value } = event.target;

    setForm((currentForm) => ({
      ...currentForm,
      [name]: value,
    }));
  }

  function handleSubmit(event) {
    event.preventDefault();

    const name = form.name.trim();
    const category = form.category.trim();
    const price = Number(form.price);
    const quantity = Number(form.quantity);

    if (!name || !category || Number.isNaN(price) || Number.isNaN(quantity)) {
      setFeedback("Please complete every field before saving.");
      return;
    }

    if (price < 0 || quantity < 0) {
      setFeedback("Price and quantity must stay at zero or above.");
      return;
    }

    const savedProduct = {
      id: editingId ?? Date.now(),
      name,
      category,
      price: Number(price.toFixed(2)),
      quantity: Math.floor(quantity),
    };

    // Replace these local updates with axios calls when your FastAPI routes are ready.
    if (isEditing) {
      setProducts((currentProducts) =>
        currentProducts.map((product) =>
          product.id === editingId ? savedProduct : product
        )
      );
      setFeedback(`Updated "${savedProduct.name}" successfully.`);
    } else {
      setProducts((currentProducts) => [savedProduct, ...currentProducts]);
      setFeedback(`Added "${savedProduct.name}" successfully.`);
    }

    resetForm();
  }

  function handleEdit(product) {
    setEditingId(product.id);
    setForm({
      name: product.name,
      category: product.category,
      price: String(product.price),
      quantity: String(product.quantity),
    });
    setFeedback(`Editing "${product.name}". Update the form and save your changes.`);
  }

  function handleDelete(productId) {
    const productToDelete = products.find((product) => product.id === productId);

    if (!productToDelete) {
      return;
    }

    if (!window.confirm(`Delete "${productToDelete.name}" from the list?`)) {
      return;
    }

    // Replace this local update with an axios delete request later.
    setProducts((currentProducts) =>
      currentProducts.filter((product) => product.id !== productId)
    );

    if (editingId === productId) {
      resetForm();
    }

    setFeedback(`Deleted "${productToDelete.name}".`);
  }

  function restoreDemoData() {
    setProducts(DEFAULT_PRODUCTS);
    setSearchTerm("");
    resetForm();
    setFeedback("Sample products have been restored.");
  }

  return (
    <div className="app-shell">
      <header className="hero">
        <div className="hero-card">
          <div className="hero-copy">
            <span className="badge">Frontend Only</span>
            <h1>Inventory CRUD Practice</h1>
            <p>
              This screen works right away with browser data so you can practice
              the UI first, then connect your own FastAPI backend when you are ready.
            </p>
          </div>

          <div className="hero-actions">
            <button className="btn btn-secondary" type="button" onClick={restoreDemoData}>
              Reset sample data
            </button>
          </div>
        </div>

        <div className="stats-grid">
          <article className="stat-card">
            <span className="stat-label">Products</span>
            <strong>{totalProducts}</strong>
          </article>

          <article className="stat-card">
            <span className="stat-label">Units in stock</span>
            <strong>{totalUnits}</strong>
          </article>

          <article className="stat-card">
            <span className="stat-label">Low stock items</span>
            <strong>{lowStockCount}</strong>
          </article>

          <article className="stat-card">
            <span className="stat-label">Inventory value</span>
            <strong>{currencyFormatter.format(inventoryValue)}</strong>
          </article>
        </div>
      </header>

      <main className="workspace">
        <section className="panel">
          <div className="panel-header">
            <div>
              <h2>{isEditing ? "Edit product" : "Add a product"}</h2>
              <p>Use the form for create and update actions.</p>
            </div>
          </div>

          <div className="status-banner">{feedback}</div>

          <form className="product-form" onSubmit={handleSubmit}>
            <label className="field">
              <span>Product name</span>
              <input
                name="name"
                type="text"
                placeholder="Wireless Mouse"
                value={form.name}
                onChange={handleInputChange}
              />
            </label>

            <label className="field">
              <span>Category</span>
              <input
                name="category"
                type="text"
                placeholder="Accessories"
                value={form.category}
                onChange={handleInputChange}
              />
            </label>

            <div className="field-grid">
              <label className="field">
                <span>Price</span>
                <input
                  name="price"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="39.99"
                  value={form.price}
                  onChange={handleInputChange}
                />
              </label>

              <label className="field">
                <span>Quantity</span>
                <input
                  name="quantity"
                  type="number"
                  min="0"
                  step="1"
                  placeholder="8"
                  value={form.quantity}
                  onChange={handleInputChange}
                />
              </label>
            </div>

            <div className="button-row">
              <button className="btn btn-primary" type="submit">
                {isEditing ? "Update product" : "Add product"}
              </button>

              <button className="btn btn-ghost" type="button" onClick={resetForm}>
                Clear form
              </button>
            </div>
          </form>

          <div className="integration-card">
            <h3>FastAPI route idea</h3>
            <ul className="endpoint-list">
              <li>
                <code>GET /products</code>
              </li>
              <li>
                <code>POST /products</code>
              </li>
              <li>
                <code>PUT /products/{"{id}"}</code>
              </li>
              <li>
                <code>DELETE /products/{"{id}"}</code>
              </li>
            </ul>

            <pre className="payload-example">{`{
  "name": "Notebook Stand",
  "category": "Desk Setup",
  "price": 39.99,
  "quantity": 8
}`}</pre>
          </div>
        </section>

        <section className="panel">
          <div className="panel-header panel-header-spread">
            <div>
              <h2>Products</h2>
              <p>Edit or delete any row from the list.</p>
            </div>

            <label className="search-field">
              <span>Search</span>
              <input
                type="text"
                placeholder="Search by name or category"
                value={searchTerm}
                onChange={(event) => setSearchTerm(event.target.value)}
              />
            </label>
          </div>

          {filteredProducts.length === 0 ? (
            <div className="empty-state">
              <h3>No products matched your search.</h3>
              <p>Try a different keyword or add a new product from the form.</p>
            </div>
          ) : (
            <div className="table-wrap">
              <table className="product-table">
                <thead>
                  <tr>
                    <th>Product</th>
                    <th>Price</th>
                    <th>Qty</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>

                <tbody>
                  {filteredProducts.map((product) => (
                    <tr key={product.id}>
                      <td>
                        <div className="row-title">{product.name}</div>
                        <div className="row-subtitle">{product.category}</div>
                      </td>
                      <td>{currencyFormatter.format(product.price)}</td>
                      <td>{product.quantity}</td>
                      <td>
                        <span className={`pill pill-${getStockTone(product.quantity)}`}>
                          {getStockLabel(product.quantity)}
                        </span>
                      </td>
                      <td className="actions-cell">
                        <button
                          className="table-btn"
                          type="button"
                          onClick={() => handleEdit(product)}
                        >
                          Edit
                        </button>
                        <button
                          className="table-btn table-btn-danger"
                          type="button"
                          onClick={() => handleDelete(product.id)}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </section>
      </main>
    </div>
  );
}

export default App;
